import { loadConfig, requireLiveConfig } from './config.js';
import { buildReviewTask, runReview, type ReviewTarget } from './runner.js';
import { createComposioClient, createGithubConnectUrl, getActiveGithubConnection } from './workbench.js';

type Command = 'review' | 'connect-github' | 'help';

interface CliOptions {
  command: Command;
  repo?: string;
  pr?: number;
  userId?: string;
  dryRun: boolean;
}

function usage(): string {
  return `Local PR Reviewer

Usage:
  bun run review -- --repo <owner/repo> --pr <number>
  bun run connect
  bun run smoke

Options:
  --repo <owner/repo>   GitHub repository to review
  --pr <number>         Pull request number
  --user-id <id>        Override COMPOSIO_USER_ID for this run
  --dry-run             Validate inputs and print the planned local-workbench flow
  --help                Show this message`;
}

function parseArgs(argv: string[]): CliOptions {
  const args = [...argv];
  const command = (args[0] && !args[0].startsWith('--') ? args.shift() : 'review') as Command;
  const options: CliOptions = {
    command: command === 'connect-github' || command === 'review' || command === 'help' ? command : 'help',
    dryRun: false,
  };

  for (let index = 0; index < args.length; index += 1) {
    const arg = args[index];
    const next = args[index + 1];

    if (arg === '--repo') {
      options.repo = next;
      index += 1;
    } else if (arg === '--pr') {
      options.pr = Number(next);
      index += 1;
    } else if (arg === '--user-id') {
      options.userId = next;
      index += 1;
    } else if (arg === '--dry-run') {
      options.dryRun = true;
    } else if (arg === '--help' || arg === '-h') {
      options.command = 'help';
    } else {
      throw new Error(`Unknown argument: ${arg}`);
    }
  }

  return options;
}

function parseTarget(options: CliOptions): ReviewTarget {
  if (!options.repo || !/^[^/\s]+\/[^/\s]+$/.test(options.repo)) {
    throw new Error('--repo must be in owner/repo format');
  }
  const pr = options.pr;
  if (!Number.isInteger(pr) || (pr ?? 0) <= 0) {
    throw new Error('--pr must be a positive integer');
  }
  return { repo: options.repo, pr: pr as number };
}

async function connectGithub(options: CliOptions): Promise<void> {
  const config = loadConfig();
  if (options.userId) config.userId = options.userId;
  if (!config.composioApiKey) throw new Error('COMPOSIO_API_KEY is required to create a GitHub connect URL');

  const composio = createComposioClient(config);
  const existing = await getActiveGithubConnection(composio, config.userId);
  if (existing) {
    console.log(`GitHub is already connected for ${config.userId} (${existing.id}).`);
    return;
  }

  const url = await createGithubConnectUrl(composio, config.userId);
  console.log(`Open this URL to connect GitHub for ${config.userId}:`);
  console.log(url);
}

function dryRun(target: ReviewTarget, userId: string): void {
  console.log('Dry run OK.');
  console.log(`User: ${userId}`);
  console.log(`Task: ${buildReviewTask(target)}`);
  console.log('Flow: create Tool Router session with workbench.enable=false, boot E2B, upload helper + reviewer, run checks, post one grounded PR comment.');
}

async function review(options: CliOptions): Promise<void> {
  const config = loadConfig();
  if (options.userId) config.userId = options.userId;
  const target = parseTarget(options);

  if (options.dryRun) {
    dryRun(target, config.userId);
    return;
  }

  requireLiveConfig(config);
  const result = await runReview({
    config,
    target,
    onEvent: (event) => console.log(`[${event.type}] ${event.detail}`),
  });
  console.log('\nReview result:\n');
  console.log(result);
}

async function main(): Promise<void> {
  const options = parseArgs(process.argv.slice(2));

  if (options.command === 'help') {
    console.log(usage());
    return;
  }

  if (options.command === 'connect-github') {
    await connectGithub(options);
    return;
  }

  await review(options);
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exitCode = 1;
});

import type { AppConfig } from './config.js';
import { createE2bSandbox } from './sandbox/e2b.js';
import { createComposioClient, createLocalWorkbench, requireGithubConnection } from './workbench.js';
import { executeReviewerAgent, installReviewerRuntime, uploadReviewerAgent } from './reviewer/runner.js';
import type { ReviewEventSink } from './reviewer/events.js';

export interface ReviewTarget {
  repo: string;
  pr: number;
}

export interface RunReviewOptions {
  config: AppConfig;
  target: ReviewTarget;
  onEvent?: ReviewEventSink;
}

export function buildReviewTask(target: ReviewTarget): string {
  return `Review PR #${target.pr} on ${target.repo}. Run the repository's real checks in this sandbox and post one grounded GitHub PR comment only if checks actually run.`;
}

export async function runReview(options: RunReviewOptions): Promise<string> {
  const onEvent = options.onEvent ?? (() => {});
  const composio = createComposioClient(options.config);

  onEvent({ type: 'info', detail: 'checking GitHub connection' });
  await requireGithubConnection(composio, options.config.userId);

  onEvent({ type: 'info', detail: 'creating local workbench session' });
  const workbench = await createLocalWorkbench(composio, options.config.userId);

  onEvent({ type: 'sandbox', detail: 'booting E2B sandbox' });
  const sandbox = await createE2bSandbox({
    apiKey: options.config.e2bApiKey ?? '',
    timeoutMs: options.config.e2bTimeoutMs,
    remoteDir: options.config.sandboxRemoteDir,
    helperSource: workbench.helperSource,
    env: workbench.env,
  });

  try {
    await uploadReviewerAgent(sandbox);
    await installReviewerRuntime(sandbox, onEvent);
    return await executeReviewerAgent(
      sandbox,
      buildReviewTask(options.target),
      {
        OPENAI_API_KEY: options.config.openaiApiKey ?? '',
        COMPOSIO_USER_ID: options.config.userId,
      },
      onEvent
    );
  } finally {
    onEvent({ type: 'sandbox', detail: 'tearing down sandbox' });
    await sandbox.teardown();
  }
}

import { Composio } from '@composio/core';
import {
  experimental_createLocalWorkbenchSession,
  type LocalWorkbenchSession,
} from '@composio/experimental/workbench';
import type { AppConfig } from './config.js';

type ConnectedAccount = {
  id: string;
  status?: string;
};

export function createComposioClient(config: AppConfig): Composio {
  return new Composio({
    apiKey: config.composioApiKey,
    baseURL: config.composioBaseUrl,
  });
}

export async function getActiveGithubConnection(composio: Composio, userId: string): Promise<ConnectedAccount | undefined> {
  const list = (await composio.connectedAccounts.list({
    userIds: [userId],
    toolkitSlugs: ['github'],
    statuses: ['ACTIVE'],
  })) as { items?: ConnectedAccount[] };

  return list.items?.[0];
}

export async function createGithubConnectUrl(composio: Composio, userId: string): Promise<string> {
  const request = await composio.toolkits.authorize(userId, 'github');
  if (!request.redirectUrl) throw new Error('Composio did not return a GitHub connect URL');
  return request.redirectUrl;
}

export async function requireGithubConnection(composio: Composio, userId: string): Promise<ConnectedAccount> {
  const account = await getActiveGithubConnection(composio, userId);
  if (account) return account;

  const url = await createGithubConnectUrl(composio, userId);
  throw new Error(
    [
      `No active GitHub connection found for COMPOSIO_USER_ID="${userId}".`,
      'Open this URL, complete GitHub authorization, then run the reviewer again:',
      url,
    ].join('\n')
  );
}

export async function createLocalWorkbench(composio: Composio, userId: string): Promise<LocalWorkbenchSession> {
  // Create the session with the remote workbench disabled so code execution runs in our own sandbox,
  // then hand it to the helper (which validates workbench.enable === false).
  const session = await composio.sessions.create(userId, {
    toolkits: ['github'],
    workbench: { enable: false },
  });
  return experimental_createLocalWorkbenchSession(composio, session);
}

import { Sandbox } from 'e2b';

export interface SandboxOptions {
  apiKey: string;
  timeoutMs: number;
  remoteDir: string;
  helperSource: string;
  env: Record<string, string>;
}

export interface UserSandbox {
  remoteDir: string;
  env: Record<string, string>;
  writeFile(path: string, contents: string): Promise<void>;
  run(command: string, options?: RunOptions): Promise<void>;
  teardown(): Promise<void>;
}

export interface RunOptions {
  timeoutMs?: number;
  env?: Record<string, string>;
  onStdout?: (chunk: string) => void;
  onStderr?: (chunk: string) => void;
}

type CommandError = {
  result?: {
    exitCode?: number;
    stdout?: string;
    stderr?: string;
  };
};

export function shellQuote(value: string): string {
  return `'${value.replace(/'/g, `'\\''`)}'`;
}

export function commandErrorText(error: unknown): string {
  const result = (error as CommandError).result;
  if (result) {
    const output = result.stderr || result.stdout || '';
    return `exit ${result.exitCode ?? 'unknown'}\n${output.slice(-1200)}`;
  }
  return error instanceof Error ? error.message : String(error);
}

export async function createE2bSandbox(options: SandboxOptions): Promise<UserSandbox> {
  const sandbox = await Sandbox.create({
    apiKey: options.apiKey,
    timeoutMs: options.timeoutMs,
  });

  await sandbox.commands.run(`mkdir -p ${shellQuote(options.remoteDir)}`, {
    timeoutMs: 30_000,
  });
  await sandbox.files.write(`${options.remoteDir}/composio_helper.py`, options.helperSource);

  return {
    remoteDir: options.remoteDir,
    env: options.env,
    async writeFile(path, contents) {
      await sandbox.files.write(path, contents);
    },
    async run(command, runOptions = {}) {
      await sandbox.commands.run(command, {
        timeoutMs: runOptions.timeoutMs,
        envs: runOptions.env,
        onStdout: runOptions.onStdout,
        onStderr: runOptions.onStderr,
      });
    },
    async teardown() {
      await sandbox.kill();
    },
  };
}

import 'dotenv/config';

export interface AppConfig {
  composioApiKey?: string;
  composioBaseUrl?: string;
  openaiApiKey?: string;
  e2bApiKey?: string;
  userId: string;
  sandboxRemoteDir: string;
  e2bTimeoutMs: number;
}

const DEFAULT_USER_ID = 'local-pr-reviewer-user';
const DEFAULT_REMOTE_DIR = '/home/user/local-pr-reviewer';
const DEFAULT_E2B_TIMEOUT_MS = 1_800_000;

function optionalEnv(name: string): string | undefined {
  const value = process.env[name];
  return value && value.trim() ? value.trim() : undefined;
}

function optionalNumberEnv(name: string, fallback: number): number {
  const value = optionalEnv(name);
  if (!value) return fallback;

  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    throw new Error(`${name} must be a positive number`);
  }
  return parsed;
}

export function loadConfig(): AppConfig {
  return {
    composioApiKey: optionalEnv('COMPOSIO_API_KEY'),
    composioBaseUrl: optionalEnv('COMPOSIO_BASE_URL'),
    openaiApiKey: optionalEnv('OPENAI_API_KEY'),
    e2bApiKey: optionalEnv('E2B_API_KEY'),
    userId: optionalEnv('COMPOSIO_USER_ID') ?? DEFAULT_USER_ID,
    sandboxRemoteDir: optionalEnv('SANDBOX_REMOTE_DIR') ?? DEFAULT_REMOTE_DIR,
    e2bTimeoutMs: optionalNumberEnv('E2B_TIMEOUT_MS', DEFAULT_E2B_TIMEOUT_MS),
  };
}

export function requireLiveConfig(config: AppConfig): Required<Pick<AppConfig, 'composioApiKey' | 'openaiApiKey' | 'e2bApiKey'>> {
  const missing = [
    ['COMPOSIO_API_KEY', config.composioApiKey],
    ['OPENAI_API_KEY', config.openaiApiKey],
    ['E2B_API_KEY', config.e2bApiKey],
  ]
    .filter(([, value]) => !value)
    .map(([name]) => name);

  if (missing.length) {
    throw new Error(`Missing required env var${missing.length === 1 ? '' : 's'} for a live run: ${missing.join(', ')}`);
  }

  return {
    composioApiKey: config.composioApiKey,
    openaiApiKey: config.openaiApiKey,
    e2bApiKey: config.e2bApiKey,
  } as Required<Pick<AppConfig, 'composioApiKey' | 'openaiApiKey' | 'e2bApiKey'>>;
}

import { readFile } from 'node:fs/promises';
import { join } from 'node:path';
import { parseAgentEvent, type ReviewEventSink } from './events.js';
import { commandErrorText, shellQuote, type UserSandbox } from '../sandbox/e2b.js';

const INSTALL_TIMEOUT_MS = 300_000;
const AGENT_TIMEOUT_MS = 1_500_000;
const AGENT_DIR = join(process.cwd(), 'agent');

const AGENT_FILES = [
  ['agent.ts', 'agent.ts'],
  ['instructions.md', 'instructions.md'],
  ['package.json', 'package.json'],
] as const;

function createOutputCollector(onEvent: ReviewEventSink) {
  let output = '';

  return {
    onStdout(data: string) {
      output += data;

      for (const line of data.split('\n')) {
        if (!line.trim()) continue;

        const event = parseAgentEvent(line);
        if (event) onEvent(event);
        else console.log(line);
      }
    },

    onStderr(data: string) {
      output += data;
      for (const line of data.split('\n')) {
        if (line.trim()) console.error(line);
      }
    },

    result() {
      const match = output.match(/::result::(.*)$/m);
      if (!match) return undefined;

      try {
        return JSON.parse(match[1]) as string;
      } catch {
        return match[1];
      }
    },

    tail() {
      return output.slice(-2000);
    },
  };
}

export async function uploadReviewerAgent(sandbox: UserSandbox): Promise<void> {
  await Promise.all(
    AGENT_FILES.map(async ([localName, remoteName]) => {
      const contents = await readFile(join(AGENT_DIR, localName), 'utf8');
      await sandbox.writeFile(`${sandbox.remoteDir}/${remoteName}`, contents);
    })
  );
}

export async function installReviewerRuntime(sandbox: UserSandbox, onEvent: ReviewEventSink): Promise<void> {
  onEvent({ type: 'info', detail: 'installing reviewer runtime' });

  try {
    await sandbox.run(`cd ${shellQuote(sandbox.remoteDir)} && npm install --no-audit --no-fund --loglevel=error`, {
      timeoutMs: INSTALL_TIMEOUT_MS,
    });
  } catch (error) {
    throw new Error(`npm install failed:\n${commandErrorText(error)}`);
  }
}

export async function executeReviewerAgent(
  sandbox: UserSandbox,
  task: string,
  env: Record<string, string>,
  onEvent: ReviewEventSink
): Promise<string> {
  onEvent({ type: 'run', detail: 'reviewer running inside your sandbox' });

  const output = createOutputCollector(onEvent);
  try {
    await sandbox.run(`cd ${shellQuote(sandbox.remoteDir)} && npx --yes tsx agent.ts`, {
      timeoutMs: AGENT_TIMEOUT_MS,
      env: {
        ...sandbox.env,
        ...env,
        AGENT_REMOTE_DIR: sandbox.remoteDir,
        TASK: task,
      },
      onStdout: output.onStdout,
      onStderr: output.onStderr,
    });
  } catch (error) {
    const result = output.result();
    if (result) return result;
    throw new Error(`agent run failed:\n${commandErrorText(error)}`);
  }

  return output.result() ?? output.tail() ?? '(no output)';
}

import { Agent, run, tool } from '@openai/agents';
import { execSync } from 'node:child_process';
import { readFileSync, writeFileSync } from 'node:fs';

const REMOTE = process.env.AGENT_REMOTE_DIR || '/home/user/local-pr-reviewer';
const CELL_TIMEOUT_MS = 900_000;
const MAX_BUFFER_BYTES = 32 * 1024 * 1024;
const TASK = process.env.TASK || 'Review the pull request.';
const INSTRUCTIONS = readFileSync(new URL('./instructions.md', import.meta.url), 'utf8');

type RunPythonInput = {
  note: string;
  code: string;
};

type ExecError = {
  status?: number;
  stdout?: string;
  stderr?: string;
};

let cellNumber = 0;

function nextCellFile(): string {
  cellNumber += 1;
  return `cell-${cellNumber}.py`;
}

function cellLabel(file: string): string {
  return file.replace('cell-', 'cell ').replace('.py', '');
}

function buildCellSource(code: string): string {
  return [
    'from composio_helper import run_composio_tool, invoke_llm, web_search',
    'import json',
    'import os',
    'import pathlib',
    'import shutil',
    'import subprocess',
    'import textwrap',
    '',
    'def run(cmd, cwd=None, timeout=900):',
    '    completed = subprocess.run(cmd, cwd=cwd, shell=True, text=True, capture_output=True, timeout=timeout)',
    '    output = (completed.stdout or "") + (completed.stderr or "")',
    '    print(output[-12000:])',
    '    return {"exit_code": completed.returncode, "output": output}',
    '',
    code,
    '',
  ].join('\n');
}

function summarizeFailure(error: ExecError): string {
  return (error.stderr || error.stdout || '').trim().split('\n').slice(-3).join(' | ').slice(-300);
}

function runCell(file: string): string {
  return execSync(`python3 ${file}`, {
    cwd: REMOTE,
    encoding: 'utf8',
    timeout: CELL_TIMEOUT_MS,
    maxBuffer: MAX_BUFFER_BYTES,
    shell: '/bin/bash',
  });
}

const runPython = tool({
  name: 'run_python',
  description:
    'Execute a Python cell in THIS sandbox. Pre-imported and in scope: ' +
    '`run_composio_tool(slug, arguments)` to call Composio tools, `invoke_llm(query)`, `web_search(query)`, ' +
    '`run(cmd, cwd=None, timeout=900)` for shell commands, and Python stdlib modules json/os/pathlib/shutil/subprocess/textwrap. ' +
    'Print anything you want to observe; stdout+stderr are returned to you.',
  parameters: {
    type: 'object',
    properties: {
      note: {
        type: 'string',
        description:
          'A short present-tense description of what this cell does, shown live to the user (<=10 words). ' +
          'e.g. "fetching PR #1 metadata", "downloading repo archive", "running node --test", "posting review comment".',
      },
      code: { type: 'string', description: 'Python to run. Do not include markdown fences.' },
    },
    required: ['note', 'code'],
    additionalProperties: false,
  },
  strict: true,
  execute: async (raw: unknown) => {
    const { note, code } = raw as RunPythonInput;
    const file = nextCellFile();

    console.log(`::event::step::${note} (${cellLabel(file)})`);
    writeFileSync(`${REMOTE}/${file}`, buildCellSource(code));

    try {
      return runCell(file);
    } catch (e: unknown) {
      const error = e as ExecError;
      console.log(`::event::error::${note} failed: ${summarizeFailure(error)}`);
      return `exit ${error.status}\n--- stdout ---\n${error.stdout ?? ''}\n--- stderr ---\n${error.stderr ?? ''}`;
    }
  },
});

const agent = new Agent({
  name: 'Local PR Reviewer',
  instructions: INSTRUCTIONS,
  tools: [runPython],
});

const result = await run(agent, TASK, { maxTurns: 40 });
console.log('::result::' + JSON.stringify(result.finalOutput ?? '(no output)'));
